for (int i = 0; i <= server_num; i++) {
    listen_ctx_t *listen_ctx = &listen_ctx_list[i];
    if (mode != UDP_ONLY) {
        ev_io_stop(loop, &listen_ctx->io);
        close(listen_ctx->fd);
    }
}

if (mode != UDP_ONLY) {
    free_connections(loop);
}

if (mode != TCP_ONLY) {
